-- Enrichment marathon batch: Nhost, NiceJob, Nightwatch, Nimble, NinjaOne, Ninox, Nitro PDF Pro, NocoDB

-- ── Nhost ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nhost is an open-source backend-as-a-service platform that bundles a managed Postgres database, an instant GraphQL API powered by Hasura, authentication, file storage, and serverless functions into a single developer platform.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $25/month)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Stockholm, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nhost Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nhost review 2026: see how this open-source Postgres and GraphQL backend platform compares on features, pricing tiers, and top Firebase and Supabase alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nhost is an open-source backend-as-a-service (BaaS) platform founded in 2019 and headquartered in Stockholm, Sweden. It positions itself as an open-source alternative to Google Firebase, built around PostgreSQL rather than a proprietary NoSQL store. The core product bundles five components into one managed platform: a dedicated PostgreSQL database per project, an automatically generated GraphQL API powered by the open-source Hasura GraphQL Engine (with realtime subscriptions and granular row-level permissions), an authentication service supporting email/password, magic links, and OAuth providers such as Google and GitHub, an S3-compatible file storage service, and serverless Functions written in Node.js/TypeScript that run alongside the API. Nhost also ships a CLI and Infrastructure-as-Code tooling so developers can run a full local development environment and deploy changes through git-based workflows. In April 2021 Nhost raised a 3 million dollar seed round led by Nauta Capital, with participation from Antler and angel investors including the founders of GitHub and Netlify, underscoring its positioning as developer-first infrastructure. The company is a small, distributed team; public revenue trackers have reported roughly 660,000 dollars in annual revenue on a team of around six people in 2025, indicating a lean, profitable-leaning operation rather than a heavily headcount-scaled one. Pricing runs on a freemium model: a free Starter tier offers 1 GB database, 1 GB storage, and 5 GB egress on a single project that pauses after a week of inactivity; the Pro tier starts at 25 dollars per month (including 15 dollars of compute credits) and adds automated backups, point-in-time recovery, and managed Grafana observability; a Team tier starting at 599 dollars per month adds SOC 2 Type II compliance, SLA-backed support, and external database connectivity; and Enterprise is custom-priced with dedicated clusters and a technical account manager. Nhost targets indie developers, startups, and small-to-medium engineering teams who want a Postgres-native backend without operating their own infrastructure, competing directly with Supabase (its closest analog, also Postgres-based), Firebase, Hasura Cloud, AWS Amplify, and Appwrite. Its main differentiators versus Supabase are its native, tight integration with Hasura's GraphQL engine (versus Supabase's REST/PostgREST-first approach) and its emphasis on GraphQL as the primary API layer. Because the entire stack -- database schema, Hasura metadata, auth configuration, and functions -- is open source and self-hostable, Nhost also appeals to teams wanting to avoid vendor lock-in while still using a managed cloud offering for production workloads.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ea768a9c-a511-4333-8959-87593d0426a5';

