-- ── Nimble ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nimble is a relationship-focused CRM for small businesses that unifies contacts, social signals, email, and pipeline management, with deep integration into Microsoft 365 and Google Workspace.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$24.90/seat/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Santa Monica, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nimble Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nimble CRM review 2026: explore this small-business relationship management platform's features, pricing, integrations, pros and cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nimble is a relationship-focused CRM founded in 2009 and headquartered in Santa Monica, California. Its founder and CEO, Jon Ferrara, previously co-founded GoldMine, one of the earliest contact-management CRM products, in 1989, and sold it for a reported 125 million dollars before starting Nimble to bring a similar founder-led, relationship-first philosophy to a modern, socially-connected CRM. Nimble differentiates itself from larger CRMs like Salesforce and HubSpot by emphasizing simplicity and deep integration with the tools small businesses already use daily, particularly Microsoft 365 and Google Workspace, through a browser extension called Nimble Prospector that lets users capture contact and company data from any web page, social profile, or inbox. The platform combines contact management, deal and pipeline tracking, email marketing and sequencing, and social signal enrichment (pulling in social media activity and company data to build a fuller picture of each contact) into one system, with AI-powered features for drafting emails and summarizing relationship history. Nimble's core Business plan is priced at 24.90 dollars per seat per month billed annually (or 29.90 dollars per seat billed monthly), and includes 25,000 contact records, 2 GB of storage per seat, Microsoft 365 and Google Workspace integration, the Nimble Prospector browser extension, and 1,000 group messages per license per month, with a 14-day free trial requiring no credit card. Beyond the base plan, Nimble offers a la carte add-ons rather than multiple rigid tiers: email marketing (15 dollars per month company-wide, unlimited sends), web forms and live chat (12 dollars per month per team), data enrichment credits (10 dollars per month for 100 credits), additional contact capacity (10 dollars per month per additional 10,000 contacts), extra storage (10 dollars per month per additional 10 GB), and larger group-messaging packages (15 to 99 dollars per month for 2,000 to 25,000 emails). This modular pricing lets small businesses pay only for the capacity and features they need as they grow. Nimble's target audience is small businesses and solopreneurs, particularly those who already run their business communication through Microsoft 365 or Google Workspace and want a CRM that layers on top of existing email and calendar workflows rather than replacing them. The company is headquartered in Santa Monica with an employee count generally estimated in the low hundreds. Its primary competitors include HubSpot CRM, Zoho CRM, Insightly, Pipedrive, and Salesforce, with Nimble's key differentiators being its social-signal-driven contact enrichment, tight Office 365/Google Workspace integration, and a founder-led company culture inherited from Jon Ferrara's earlier success building GoldMine.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f3558245-b91d-4875-b0dc-3842ac4f3805';

