INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Managed Postgres database$q$, $q$Each project gets a dedicated PostgreSQL instance rather than a shared or proprietary datastore, giving developers full SQL access and standard relational tooling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Instant GraphQL API via Hasura$q$, $q$The open-source Hasura GraphQL Engine auto-generates queries, mutations, and realtime subscriptions directly from the database schema, with granular role-based permissions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Built-in authentication$q$, $q$Supports email and password, passwordless magic links, and OAuth providers such as Google and GitHub, with unlimited authenticated users on every plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$S3-compatible file storage$q$, $q$Upload, transform, and serve files and media through a storage service that integrates directly with the auth and permissions layer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Serverless Functions$q$, $q$Custom backend logic can be written in Node.js or TypeScript and deployed as serverless functions that run alongside the GraphQL API.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$CLI and Infrastructure as Code$q$, $q$A local development CLI mirrors the cloud environment, and configuration can be version-controlled and deployed through git-based workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Realtime subscriptions$q$, $q$GraphQL subscriptions push live data updates to connected clients automatically whenever underlying rows change, without manual WebSocket setup.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Remote schema stitching$q$, $q$External REST APIs and other GraphQL services can be merged into a single unified Nhost GraphQL endpoint.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Fully open source and self-hostable, reducing vendor lock-in risk$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Built on standard PostgreSQL rather than a proprietary database format$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$GraphQL API is generated automatically, saving significant backend development time$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Generous free tier suitable for prototypes and small projects$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Backed by well-known angel investors from GitHub and Netlify, signaling strong developer-tooling pedigree$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Smaller team and ecosystem than larger competitors like Supabase or Firebase, which may mean slower feature velocity$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$GraphQL-first approach requires familiarity with GraphQL and Hasura concepts, which adds a learning curve for teams used to REST$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Jump from Pro to Team pricing (25 dollars to 599 dollars per month) is steep for growing teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Free tier projects pause after a week of inactivity, which can be disruptive for infrequently used demos$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Smaller community and fewer third-party integrations compared to more established BaaS platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$What is Nhost used for?$q$, $q$Nhost is used as a backend-as-a-service for web and mobile apps, providing a managed Postgres database, an auto-generated GraphQL API, authentication, file storage, and serverless functions so developers do not need to build and host their own backend infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Is Nhost open source?$q$, $q$Yes. Nhost's core stack, including its database tooling, Hasura-based GraphQL layer, authentication service, and storage service, is open source and can be self-hosted, in addition to being available as a managed cloud service.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$How is Nhost different from Supabase?$q$, $q$Both are open-source, Postgres-based backend platforms, but Nhost centers its API layer on GraphQL through Hasura, while Supabase centers its API layer on REST through PostgREST. Teams that prefer GraphQL as their primary API paradigm tend to gravitate toward Nhost.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Does Nhost have a free plan?$q$, $q$Yes, Nhost offers a free Starter plan with 1 GB of database storage, 1 GB of file storage, and 5 GB of egress, suitable for small projects and prototypes, though the single free project pauses after a week of inactivity.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$What programming languages does Nhost support for functions?$q$, $q$Nhost serverless Functions are written in Node.js using JavaScript or TypeScript.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Who is behind Nhost?$q$, $q$Nhost is a Stockholm, Sweden-based startup founded in 2019 that raised a 3 million dollar seed round in 2021 led by Nauta Capital, with angel backing from the founders of GitHub and Netlify.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Does Nhost support realtime data?$q$, $q$Yes, through GraphQL subscriptions, Nhost pushes live updates to connected clients automatically whenever the underlying database rows change, without requiring custom WebSocket infrastructure.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Startup MVP backend$q$, $q$Early-stage startups use Nhost to stand up a full backend, database, auth, and API in days instead of weeks, letting small engineering teams focus on the frontend and product experience.$q$, $q$Startup founders and small engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$GraphQL-first applications$q$, $q$Teams already committed to a GraphQL API layer use Nhost to get an instant, permission-aware GraphQL endpoint generated directly from their Postgres schema, avoiding hand-written resolvers.$q$, $q$Frontend and full-stack developers building GraphQL clients$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Self-hosted backend for regulated environments$q$, $q$Because the stack is open source, organizations with data residency or compliance requirements can self-host Nhost's components on their own infrastructure instead of using the managed cloud.$q$, $q$Enterprises and regulated industries with strict data control needs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 GB database","1 GB storage","5 GB egress","Unlimited users and OAuth providers","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Pro$q$, $q$$25/month$q$, $q$monthly$q$, NULL, $q$["Includes $15 in compute credits","10 GB database, 50 GB storage, 50 GB egress","Automated backups and point-in-time recovery","Managed Grafana metrics","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Team$q$, $q$$599/month$q$, $q$monthly$q$, NULL, $q$["SOC 2 Type II compliance","SLA-backed email support","Dedicated Discord channel","External database connectivity"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Service Level Agreements","Dedicated technical account manager","Dedicated clusters available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nhost is an open-source backend platform built to give developers a production-ready backend without writing custom server code. At its core is a managed PostgreSQL database paired with the Hasura GraphQL Engine, which automatically exposes the database schema as a fully-featured GraphQL API complete with realtime subscriptions and fine-grained permissions.$q$, $q$Founded in 2019 and based in Stockholm, Sweden, Nhost is frequently described as an open-source alternative to Firebase, but with a relational Postgres foundation instead of a proprietary NoSQL database. The platform bundles authentication, file storage, and serverless functions alongside the database and API, so teams can build a complete application backend from a single dashboard and CLI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The GraphQL API is generated directly from the Postgres schema, meaning developers get queries, mutations, and live subscriptions as soon as tables are created, without hand-writing resolvers. Row-level permissions can be attached per role, and remote schemas let teams stitch in third-party APIs or legacy services alongside their own data.$q$, $q$Authentication supports email and password, passwordless magic links, and OAuth sign-in with providers like Google and GitHub, with unlimited users included even on the free tier. Storage is S3-compatible for files and media, and serverless Functions written in Node.js or TypeScript can run custom business logic that hooks into the same GraphQL layer, all deployable through the Nhost CLI and git-based Infrastructure-as-Code workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nhost uses a usage-based freemium model. The free Starter plan is meant for prototyping and side projects, capped at 1 GB of database storage and 1 GB of file storage on a single project that pauses after a week without traffic.$q$, $q$Paid plans begin with Pro at 25 dollars per month, which raises resource limits and adds automated backups and monitoring, followed by Team at 599 dollars per month for SOC 2 compliance and SLA support, and a custom-quoted Enterprise tier for dedicated infrastructure and account management.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Automated review requests$q$, $q$Sends timed text and email requests asking recent customers to leave a review, with automated follow-up reminders to increase response rates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Multi-platform review monitoring$q$, $q$Tracks new reviews across Google, Facebook, and other major platforms from a single dashboard so businesses never miss feedback.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Social proof widgets$q$, $q$Automatically displays recent positive reviews on the business's website to build trust with prospective customers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Branded microsite$q$, $q$Generates a shareable microsite that showcases a business's best reviews, useful for social media and marketing campaigns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Referral automation$q$, $q$Encourages happy customers to refer new business through automated, trackable referral campaigns (available on Pro plan).$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$AI-assisted review responses$q$, $q$Uses AI to help draft timely responses to customer reviews, reducing the manual effort of reputation management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$NPS surveys$q$, $q$Collects Net Promoter Score feedback to identify at-risk customers and advocates beyond simple star ratings (Pro plan).$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Staff leaderboards$q$, $q$Gamifies review generation by ranking staff members on review volume and ratings to encourage friendly competition.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Purpose-built for local service businesses with straightforward setup$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Combines review generation with referral and gifting automation, not just review requests$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Includes social proof widgets and a shareable microsite out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$14-day free trial with no long-term contract required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Backed by Paystone's broader payments and customer engagement ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Pricing is higher than some basic review-request-only tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Website bundle plans carry an additional one-time setup fee$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Advanced features like referrals and NPS surveys are locked behind the higher Pro tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Primarily focused on English-language markets and North American review platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Multi-location and franchise pricing requires a custom quote rather than transparent published rates$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$What does NiceJob do?$q$, $q$NiceJob automates review requests, review monitoring, referral campaigns, and social proof marketing to help local service businesses build their online reputation and win more customers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$How much does NiceJob cost?$q$, $q$NiceJob's Reviews plan starts at 75 dollars per month, with a Pro plan at 125 dollars per month that adds referrals, gifting, and NPS surveys. Website bundle plans start at 99 dollars per month plus a 199 dollar setup fee.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Is NiceJob owned by Paystone?$q$, $q$Yes, NiceJob was acquired by Paystone, a Canadian payments and customer engagement company, in October 2021, and continues to operate under its own brand as part of Paystone's product suite.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Does NiceJob offer a free trial?$q$, $q$Yes, NiceJob offers a 14-day free trial with no credit card required and no long-term contract.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$What industries use NiceJob?$q$, $q$NiceJob is designed primarily for local service businesses such as contractors, home service companies, salons, and franchises that depend on reviews and referrals for growth.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Does NiceJob build websites?$q$, $q$Yes, through its Sites Only and Grow plus Sites bundles, NiceJob offers custom-designed, SEO-optimized websites with a personal website coach and call tracking, in addition to its core reputation marketing tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Who are NiceJob's main competitors?$q$, $q$NiceJob competes with reputation management platforms such as Birdeye, Podium, Broadly, Grade.us, and ReviewTrackers.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Automating review generation for contractors$q$, $q$Home service contractors use NiceJob to automatically request reviews after each completed job, building a steady stream of fresh testimonials without manual follow-up.$q$, $q$Home service and contracting businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Turning happy customers into referrals$q$, $q$Service businesses use NiceJob's referral and gifting automation to convert satisfied customers into new leads, reducing reliance on paid advertising.$q$, $q$Local service businesses focused on word-of-mouth growth$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Multi-location franchise reputation management$q$, $q$Franchise brands use NiceJob's custom multi-location pricing to standardize review monitoring and social proof marketing across all locations from a central dashboard.$q$, $q$Franchise owners and multi-location operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Reviews$q$, $q$$75/month$q$, $q$monthly$q$, NULL, $q$["Automated review requests and reminders","Multi-platform review monitoring","Social proof widgets","AI-assisted review responses","Staff leaderboards","Branded microsite"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Pro$q$, $q$$125/month$q$, $q$monthly$q$, NULL, $q$["All Reviews features","Automated booking reminders","Referral campaigns","Automated customer gifting","Competitor SEO insights","NPS surveys"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Sites Only$q$, $q$$99/month plus $199 setup$q$, $q$monthly$q$, NULL, $q$["Custom-designed website","SEO and mobile optimization","Personal website coach","Call tracking and lead forms"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$Grow plus Sites$q$, $q$$174/month plus $199 setup$q$, $q$monthly$q$, NULL, $q$["Full Grow reputation marketing plan","Full website management bundle"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NiceJob is a reputation marketing platform built specifically for local service businesses that rely on online reviews and referrals to win new customers. Founded in 2017 in Vancouver, Canada, the platform automates the unglamorous parts of reputation management: asking happy customers for reviews at the right moment, monitoring what gets posted across review sites, and turning that positive feedback into marketing material.$q$, $q$In 2021, NiceJob was acquired by Paystone, a Canadian payments and customer engagement company, and now operates as part of Paystone's broader suite of small-business tools while continuing to run under its own brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core loop is automated review requests sent via text or email after a completed job, paired with monitoring across major review platforms so businesses can respond quickly to feedback. Positive reviews are automatically pulled into social proof widgets for the business's website and a dedicated microsite that can be shared on social media.$q$, $q$Higher-tier plans extend beyond reviews into growth marketing: automated referral campaigns that reward customers for sending new business, automated gifting to reward loyal customers, booking reminder automation to bring customers back, and Net Promoter Score surveys to capture deeper feedback than a star rating alone.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1be3dfb4-c5d4-45dd-8fe4-1cf5db30d72d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NiceJob's core software pricing starts at 75 dollars per month for the Reviews plan and steps up to 125 dollars per month for the Pro plan, which adds referrals, gifting, and NPS surveys.$q$, $q$For businesses that also need a website, NiceJob offers bundled plans starting at 99 dollars per month plus a one-time 199 dollar setup fee, with a combined website-and-marketing bundle at 174 dollars per month. All plans include a 14-day free trial and no long-term contract.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Multi-engine rank tracking$q$, $q$Tracks keyword positions across Google, Bing, Yahoo, DuckDuckGo, and YouTube with daily updates and raw HTML snapshot verification.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Hyperlocal grid tracking$q$, $q$Monitors local search rankings down to the zip-code level across more than 107,000 locations in over 190 countries, ideal for multi-location and local SEO.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$AI visibility and citation tracking$q$, $q$Monitors brand mentions and recommendations inside AI platforms like ChatGPT, Claude, Gemini, and Perplexity, and connects those citations to traditional search rankings and traffic.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Technical site audits$q$, $q$Runs automated site audits that flag technical SEO issues and Core Web Vitals problems with smart prioritization of fixes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$White-label reporting$q$, $q$Every plan includes white-label PDF and dashboard reporting, useful for agencies reporting to clients under their own brand.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$SERP feature tracking$q$, $q$Tracks featured snippets, knowledge panels, local packs, and other SERP features alongside standard organic rankings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$NightOwl Agent automation$q$, $q$An AI-driven agent that performs competitor gap analysis and content optimization suggestions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Unlimited team seats$q$, $q$All pricing tiers include unlimited user seats with no per-seat fees, unlike many competing rank trackers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Unlimited team seats on every plan with no per-user fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Very granular local rank tracking, down to the zip-code level$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Early and dedicated investment in AI-platform visibility tracking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$White-label reporting included on all tiers, useful for agencies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$14-day free trial with full feature access$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Priced in euros, which can add currency conversion friction for some customers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Keyword caps on lower tiers can be limiting for larger sites or agencies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Smaller feature footprint outside core SEO than all-in-one suites like Semrush or Ahrefs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$AI prompt monitoring quotas are capped per plan, requiring upgrades for heavy AI-visibility tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Enterprise-grade features like SSO and dedicated account management require the top Agency tier or above$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$What is Nightwatch (nightwatch.io)?$q$, $q$Nightwatch is an SEO rank tracking and search intelligence platform that monitors keyword rankings across search engines and, more recently, AI answer engines, with a focus on hyperlocal tracking and white-label reporting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Is Nightwatch the same as Nightwatch.js?$q$, $q$No. Nightwatch.io is an SEO and search visibility product, while Nightwatch.js is a separate, unrelated open-source JavaScript end-to-end testing framework for browsers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$How much does Nightwatch cost?$q$, $q$Nightwatch's Starter plan starts at 79 euros per month for 500 keywords, with Professional at 159 euros per month and Agency at 399 euros per month; Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Does Nightwatch track AI search visibility?$q$, $q$Yes, Nightwatch monitors how brands are cited and recommended inside AI platforms including ChatGPT, Claude, Gemini, and Perplexity, and links those mentions back to traditional SEO rankings.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Does Nightwatch charge per user?$q$, $q$No, Nightwatch includes unlimited team seats on every plan, pricing instead by keyword and website volume.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Who founded Nightwatch?$q$, $q$Nightwatch was founded in 2016 in Ljubljana, Slovenia by Aljaz Fajmut, Matic Jurglic, and Steve Mingione.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Does Nightwatch offer local rank tracking?$q$, $q$Yes, Nightwatch offers highly granular local rank tracking down to the zip-code level across more than 107,000 locations worldwide.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Agency client reporting$q$, $q$SEO agencies use Nightwatch's white-label reporting and unlimited seats to manage rank tracking for multiple clients without paying per-user fees.$q$, $q$SEO and digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Multi-location local SEO tracking$q$, $q$Multi-location businesses and franchises use Nightwatch's hyperlocal grid tracking to monitor rankings at the zip-code level across every store location.$q$, $q$Multi-location and franchise businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$AI search visibility monitoring$q$, $q$Brands use Nightwatch's AI visibility tools to see how they are cited and recommended inside ChatGPT, Gemini, Claude, and Perplexity as AI-driven search grows.$q$, $q$In-house SEO and content marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Starter$q$, $q$€79/month$q$, $q$monthly (annual saves ~20%)$q$, NULL, $q$["500 keywords","5 websites","50 AI prompts/month","5 competitors per site","25 site audit pages"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Professional$q$, $q$€159/month$q$, $q$monthly (annual saves ~20%)$q$, NULL, $q$["2,500 keywords","25 websites","150 AI prompts/month","API access","White-label reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Agency$q$, $q$€399/month$q$, $q$monthly (annual saves ~20%)$q$, NULL, $q$["7,500 keywords","100 websites","500 AI prompts/month","Dedicated account manager","SSO"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["20,000+ keywords","Unlimited websites","Dedicated infrastructure","Custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nightwatch is an SEO rank tracking and search intelligence platform available at nightwatch.io, founded in 2016 in Ljubljana, Slovenia. It should not be confused with Nightwatch.js, an unrelated open-source browser automation testing framework -- this Nightwatch is a marketing and SEO product built for tracking search visibility.$q$, $q$The platform started as a highly granular local rank tracker, capable of monitoring keyword positions down to the zip-code level across more than 107,000 locations worldwide, and has since expanded into a full search intelligence suite covering traditional search engines, YouTube, and, more recently, AI answer engines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core rank tracking covers Google, Bing, Yahoo, DuckDuckGo, and YouTube with claimed 99.9 percent accuracy backed by raw HTML snapshots for verification, plus real-time refresh for priority keywords. Site audit tools flag technical SEO issues and Core Web Vitals problems with smart prioritization so teams know what to fix first.$q$, $q$Nightwatch's newer AI Visibility features monitor how a brand is mentioned and recommended inside ChatGPT, Claude, Gemini, and Perplexity, connecting those AI citations back to traditional Google rankings and downstream site traffic. Reporting is white-labeled by default across every plan, with automated daily reports, SERP feature tracking, and a Looker Studio integration for custom dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a86c30-0218-4428-94b5-d143c569c1a2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nightwatch prices per keyword volume rather than per seat, with unlimited team members included on every plan. The Starter plan costs 79 euros per month for 500 keywords and 5 websites, Professional costs 159 euros per month for 2,500 keywords and API access, and Agency costs 399 euros per month for 7,500 keywords with a dedicated account manager and SSO.$q$, $q$Enterprise pricing is custom for organizations tracking more than 20,000 keywords. Annual billing saves approximately 20 percent compared to paying monthly, and every plan includes a 14-day full-feature free trial.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Nimble Prospector browser extension$q$, $q$Captures contact, company, and social data from any web page or inbox with one click, automatically enriching CRM records.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Microsoft 365 and Google Workspace integration$q$, $q$Syncs contacts, email, and calendar data directly with the tools small businesses already use daily.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$AI-powered email creation$q$, $q$Uses AI to help draft outreach emails and summarize relationship history within a contact record.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Social signal enrichment$q$, $q$Pulls in social media activity and public data to build a fuller picture of each contact automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Pipeline and deal management$q$, $q$Tracks deals through customizable sales pipelines with visibility into stage, value, and next steps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Group messaging and email marketing$q$, $q$Sends segmented email campaigns directly from the CRM, with tiered monthly sending limits available as add-ons.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Contact and company records$q$, $q$Unifies contact history, notes, deals, and communications into a single relationship record accessible across the team.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Web forms and live chat add-on$q$, $q$Captures leads directly from a company website through embeddable forms and chat, feeding new contacts into the CRM.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Deep, native integration with Microsoft 365 and Google Workspace$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Founder-led company with a long track record in the CRM space via GoldMine$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Social signal enrichment gives richer context on contacts than basic CRMs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Modular add-on pricing lets small businesses avoid paying for unused features$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$14-day free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Single core plan with add-ons can make total cost less predictable than fixed tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Base plan's 25,000 contact and 2 GB storage limits require paid add-ons for larger businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Fewer advanced automation and reporting features than larger CRMs like HubSpot or Salesforce$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Group messaging volume is capped and requires paid upgrades for larger campaigns$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Best suited to small businesses; may lack depth for complex enterprise sales processes$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$What is Nimble CRM used for?$q$, $q$Nimble is used by small businesses to manage contacts, track sales pipelines, and enrich customer records with social and web data, all integrated with Microsoft 365 or Google Workspace email and calendars.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$How much does Nimble cost?$q$, $q$Nimble's Business plan costs 24.90 dollars per seat per month billed annually, or 29.90 dollars per seat billed monthly, with additional add-ons available for email marketing, web forms, data enrichment, and extra storage or contacts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Who founded Nimble?$q$, $q$Nimble was founded in 2009 by Jon Ferrara, who previously co-founded the early CRM pioneer GoldMine in 1989 and sold it for a reported 125 million dollars.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Does Nimble integrate with Outlook and Gmail?$q$, $q$Yes, Nimble integrates natively with both Microsoft 365 (including Outlook) and Google Workspace (including Gmail), syncing contacts, email, and calendar data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Does Nimble offer a free trial?$q$, $q$Yes, Nimble offers a 14-day free trial that does not require a credit card.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$What is Nimble Prospector?$q$, $q$Nimble Prospector is a browser extension that lets users capture contact, company, and social profile information from any webpage or inbox directly into the CRM with one click.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$How many contacts does Nimble support?$q$, $q$The base Business plan includes 25,000 contact records per account, with additional blocks of 10,000 contacts available as a paid add-on.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Solopreneur relationship management$q$, $q$Independent consultants and solopreneurs use Nimble to keep track of every contact, follow-up, and deal without needing a dedicated sales operations team.$q$, $q$Solopreneurs and independent consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Small sales team pipeline tracking$q$, $q$Small sales teams use Nimble's pipeline and deal tracking, combined with Microsoft 365 or Google Workspace sync, to manage their sales process inside tools they already use.$q$, $q$Small business sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Social-driven lead capture$q$, $q$Marketing and business development teams use Nimble Prospector to capture and enrich leads directly from social media and web browsing.$q$, $q$Small business marketing and BD teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Business (Annual)$q$, $q$$24.90/seat/month$q$, $q$annual$q$, NULL, $q$["25,000 contact records","2 GB storage per seat","Microsoft 365 and Google Workspace integration","Nimble Prospector browser extension","1,000 group messages per license/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Business (Monthly)$q$, $q$$29.90/seat/month$q$, $q$monthly$q$, NULL, $q$["Same features as annual plan","No annual commitment"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nimble is a CRM built for small businesses that want a simpler alternative to enterprise platforms like Salesforce while still getting rich contact intelligence. Founded in 2009 in Santa Monica, California by Jon Ferrara -- who earlier co-founded and sold the pioneering CRM GoldMine -- Nimble applies a similar founder-led, relationship-first philosophy to a modern, cloud-based product.$q$, $q$The platform's defining idea is unifying contact management with the communication tools small businesses already use. Rather than asking teams to abandon their inbox and calendar, Nimble integrates deeply with Microsoft 365 and Google Workspace and layers social and web-sourced data on top of every contact record.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Nimble Prospector browser extension lets users capture contact, company, and social profile data from any webpage or inbox with a single click, automatically enriching CRM records. AI-powered tools help draft emails and summarize relationship history, while pipeline and deal tracking give sales teams visibility into where opportunities stand.$q$, $q$Group messaging and email marketing tools let small teams run outreach campaigns directly from the CRM, and add-on modules for web forms, live chat, and data enrichment let businesses expand functionality as they grow rather than being forced into a higher pricing tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nimble uses a single core Business plan at 24.90 dollars per seat per month when billed annually (29.90 dollars billed monthly), which includes 25,000 contact records and 2 GB of storage per seat.$q$, $q$Rather than multiple feature-gated tiers, Nimble sells modular add-ons for email marketing, web forms and chat, data enrichment, and extra contacts or storage, letting businesses pay only for what they use beyond the base plan. A 14-day free trial is available with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Remote monitoring and management (RMM)$q$, $q$Continuously monitors the health and status of endpoints across Windows, Mac, and Linux devices, alerting IT teams to issues in real time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Automated patch management$q$, $q$Automates operating system and third-party software patching across managed devices to reduce security exposure and manual effort.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Remote access and control$q$, $q$Lets technicians remotely access and control endpoints for troubleshooting without needing physical access to the device.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$IT asset management$q$, $q$Maintains an inventory of hardware and software assets across managed environments for tracking and compliance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Endpoint backup$q$, $q$Provides backup and disaster recovery for endpoints and, through its Dropsuite acquisition, for cloud data such as Microsoft 365 and Google Workspace.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Endpoint security$q$, $q$Integrates antivirus, endpoint detection and response, and security posture management into the same console as RMM.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Software deployment$q$, $q$Automates the deployment and updating of software across fleets of managed devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Mobile device management$q$, $q$Extends management and security policies to mobile devices alongside traditional desktop and server endpoints.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Modern, fast interface widely praised relative to legacy RMM competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Free, unlimited customer support and onboarding included$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Broad platform covering RMM, patch management, backup, and security in one console$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Well-funded with strong growth, reducing risk of the vendor being acquired and discontinued$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Strong reputation among MSPs for reliability and ease of deployment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$No published, transparent pricing, requiring a sales call for even basic quotes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Per-endpoint pricing model can become expensive at very large scale without negotiated discounts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Primarily aimed at MSPs and IT teams, with less relevance for non-technical business users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Feature depth in specific areas like security can lag dedicated point solutions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Rapid acquisition-driven growth means some newer modules (like backup and security) are less mature than the core RMM product$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$What is NinjaOne used for?$q$, $q$NinjaOne is used by managed service providers and internal IT teams to remotely monitor, manage, patch, secure, and back up computers, servers, and mobile devices from a single cloud console.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$How much does NinjaOne cost?$q$, $q$NinjaOne does not publish fixed pricing; costs are quoted per endpoint and vary by product bundle and volume, with third-party reports citing a range of roughly 1.50 to 3.75 dollars per endpoint per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Who founded NinjaOne?$q$, $q$NinjaOne was founded in 2013 as NinjaRMM by Sal Sferlazza and Chris Matarese, with its platform launching publicly in 2015.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Is NinjaOne only for MSPs?$q$, $q$No, while NinjaOne is heavily used by managed service providers, it is also used by internal IT departments at mid-market and enterprise organizations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Does NinjaOne offer endpoint security?$q$, $q$Yes, NinjaOne includes endpoint security and antivirus management alongside its core RMM and patch management features.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$How much funding has NinjaOne raised?$q$, $q$NinjaOne has raised approximately 1.18 billion dollars in total funding, including a 2024 Series C round and 2025 extensions that pushed its valuation to roughly 5 billion dollars, with a reported 12.3 billion dollar valuation by mid-2026.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Does NinjaOne support Mac and Linux, or just Windows?$q$, $q$NinjaOne supports Windows, Mac, and Linux endpoints, along with mobile device management for smartphones and tablets.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$MSP client fleet management$q$, $q$Managed service providers use NinjaOne to monitor, patch, and support IT environments for dozens or hundreds of client organizations from a single console.$q$, $q$Managed service providers (MSPs)$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Internal IT operations at mid-market companies$q$, $q$Internal IT departments use NinjaOne to manage patching, remote support, and asset tracking for employee devices across distributed offices.$q$, $q$Internal IT teams at mid-market and enterprise organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Unified backup and endpoint security$q$, $q$Organizations consolidate backup, endpoint security, and RMM into NinjaOne's single platform to reduce the number of vendors and consoles IT staff must manage.$q$, $q$IT leaders consolidating their tool stack$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Custom (per endpoint)$q$, $q$Custom quote, reported ~$1.50-$3.75/endpoint/month$q$, $q$monthly or annual$q$, NULL, $q$["RMM and patch management","Remote access and control","IT asset management","Free unlimited support and onboarding","Optional add-ons for backup and security"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NinjaOne is a unified IT and endpoint management platform that grew out of NinjaRMM, founded in 2013 by Sal Sferlazza and Chris Matarese and publicly launched in 2015. Headquartered in Austin, Texas, the company has expanded well beyond its original remote monitoring and management (RMM) roots into a broader platform spanning patch management, backup, and endpoint security.$q$, $q$NinjaOne primarily serves managed service providers (MSPs) that manage IT for multiple client organizations, as well as internal IT teams at mid-market and enterprise companies. The platform is widely cited for its modern interface and ease of use compared to legacy RMM tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include remote monitoring and management of Windows, Mac, and Linux endpoints, automated patch management, IT asset inventory tracking, software deployment, and remote access and control for troubleshooting devices from anywhere. The platform also includes mobile device management for managing smartphones and tablets alongside traditional endpoints.$q$, $q$Through acquisitions and internal development, NinjaOne has added endpoint backup and disaster recovery, endpoint security and antivirus management, and IT documentation tools, positioning itself as a single console for most day-to-day IT operations rather than a point solution for any one task.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NinjaOne does not publish detailed public pricing, using a custom, per-endpoint quote model instead. Reported per-device pricing ranges from roughly 1.50 dollars per month at very high endpoint volumes down to 3.75 dollars per month for small deployments, though exact rates vary by product bundle, region, and whether the customer is an MSP reselling to end clients.$q$, $q$The company states that it withholds published rate cards partly to avoid interfering with how MSP partners price services to their own clients. All plans reportedly include free onboarding, training, and unlimited support with no hidden implementation fees.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Visual database builder$q$, $q$Lets users design relational data models and tables through a visual interface without writing SQL or backend code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Custom forms and layouts$q$, $q$Drag-and-drop tools for building custom forms, views, and dashboards tailored to specific business workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Formula-based scripting$q$, $q$A built-in scripting language allows advanced automation and calculated fields beyond what drag-and-drop alone can achieve.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Native desktop and mobile apps$q$, $q$Dedicated applications for macOS, Windows, and iOS, in addition to a web app, with offline access that syncs when reconnected.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Prebuilt templates$q$, $q$Ready-made templates for common use cases such as CRM, inventory management, and project tracking speed up initial setup.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$AI-assisted app building$q$, $q$AI tools help generate initial app structures and automations from natural-language descriptions of what a user wants to build.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Team collaboration and permissions$q$, $q$Role-based access controls let teams share databases and apps while restricting sensitive data to specific users or groups.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$API and integrations$q$, $q$Higher-tier plans include API access and third-party integrations for connecting Ninox apps to other business systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$True relational database engine, more powerful than spreadsheet-style no-code tools for complex data$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Native offline-capable apps for macOS, Windows, and iOS, not just a web app$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Free plan that never expires, good for testing before committing to a paid tier$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Strong library of templates for common business use cases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Popular and well-supported in European markets with local-language support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Steeper learning curve than pure drag-and-drop tools due to its formula/scripting layer$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Smaller ecosystem of third-party integrations compared to Airtable or Power Apps$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Per-user pricing can add up quickly for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Interface and design conventions can feel dated compared to newer no-code competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Advanced automation and admin controls are gated behind higher-priced tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$What is Ninox used for?$q$, $q$Ninox is used to build custom business applications and databases, such as CRMs, inventory systems, and project management tools, without writing traditional code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$How much does Ninox cost?$q$, $q$Ninox offers a free plan that never expires, with paid plans starting around 11 euros per user per month for Starter and 22 euros per user per month for Professional; Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Who founded Ninox?$q$, $q$Ninox was founded in 2013 by Frank Bohmer and is headquartered in Berlin, Germany.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Does Ninox work offline?$q$, $q$Yes, Ninox's native macOS, Windows, and iOS apps support offline use, syncing data automatically once the device reconnects to the internet.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Is Ninox a no-code or low-code tool?$q$, $q$Ninox is generally described as low-code: most app-building happens through visual, drag-and-drop tools, but a formula-based scripting language is available for advanced logic.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$How does Ninox compare to Airtable?$q$, $q$Ninox uses a true relational database engine and offers native offline desktop and mobile apps, while Airtable is more spreadsheet-first with a larger integration ecosystem; the choice often depends on data complexity versus integration needs.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Does Ninox offer templates?$q$, $q$Yes, Ninox provides prebuilt templates for common use cases including CRM, inventory management, and project tracking to help teams get started quickly.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Custom CRM for small businesses$q$, $q$Small businesses use Ninox to build a tailored CRM that matches their exact sales process, rather than adapting to a rigid off-the-shelf CRM.$q$, $q$Small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Field team data collection$q$, $q$Teams working in the field, such as inspectors or service technicians, use Ninox's offline-capable mobile apps to collect and sync data without needing constant connectivity.$q$, $q$Field service and inspection teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Departmental workflow apps$q$, $q$Individual departments within larger organizations use Ninox to build lightweight internal tools for tracking inventory, projects, or operations without involving central IT.$q$, $q$Departmental teams and internal operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Never expires","No credit card required","Basic database and app building"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Starter$q$, $q$~€11/user/month$q$, $q$annual (plus VAT)$q$, NULL, $q$["Custom app building","Core automation","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Professional$q$, $q$~€22/user/month$q$, $q$annual (plus VAT)$q$, NULL, $q$["Advanced automation","Integrations","Admin controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$Enterprise$q$, $q$Custom$q$, $q$annual (plus VAT)$q$, NULL, $q$["Advanced security","Dedicated support","Custom deployment options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ninox is a low-code platform for building custom business applications and databases without writing traditional code. Founded in 2013 by Frank Bohmer and headquartered in Berlin, Germany, the platform is aimed at small and mid-sized businesses that need tailored internal tools -- CRMs, inventory systems, project trackers -- but do not have dedicated software engineering resources.$q$, $q$Unlike spreadsheet-first no-code tools, Ninox is built around a genuine relational database engine paired with native applications for macOS, Windows, iOS, and the web, including offline support that syncs automatically once a device reconnects.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users design custom data models visually, then build forms, layouts, and dashboards through drag-and-drop tools, with a formula-based scripting language available for more advanced logic and automation. Pre-built templates for common use cases like CRM, project management, and inventory tracking help teams get started quickly.$q$, $q$Ninox has invested in AI-assisted app generation, letting users describe what they want to build and get a starting application structure, and it supports integrations and API access on higher tiers for connecting to other business systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ninox offers a free plan that never expires and requires no credit card, suitable for individuals or very small teams testing the platform. Paid plans start with a Starter tier around 11 euros per user per month and step up to a Professional tier around 22 euros per user per month with more automation and admin controls.$q$, $q$Enterprise pricing is custom for larger organizations needing advanced security, support, and deployment options. All paid plans are billed annually plus applicable VAT.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2929b76-2d2c-496e-a42b-392fc1b54699', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$PDF creation and editing$q$, $q$Create new PDFs or edit existing ones, including text, images, and page-level changes, within a Microsoft Office-style interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$File conversion$q$, $q$Convert PDFs to and from formats such as Word, Excel, and PowerPoint while preserving formatting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Combine and split files$q$, $q$Merge multiple documents into a single PDF or split a large PDF into separate files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Form filling and e-signature$q$, $q$Fill out PDF forms and apply legally binding electronic signatures directly within the application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$OCR (optical character recognition)$q$, $q$Converts scanned, image-based documents into searchable and editable text.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$One-time purchase licensing$q$, $q$Available as a perpetual license or multi-year term rather than requiring an ongoing monthly subscription.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Batch processing$q$, $q$Applies actions like conversion or watermarking across multiple PDF files at once to save time on repetitive tasks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Windows-native performance$q$, $q$Built specifically for Windows desktops, integrating with familiar Office-style menus and shortcuts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$One-time purchase option avoids ongoing subscription costs common with Adobe Acrobat$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Familiar Microsoft Office-style ribbon interface reduces the learning curve$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Includes OCR and e-signature tools without needing separate add-on purchases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Generally priced lower than comparable Adobe Acrobat plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Strong core PDF editing and conversion accuracy$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Windows-only; no native Mac or Linux version of the Pro desktop product$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Lacks the AI features, analytics, and team management tools available in Nitro's subscription plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$One-time license may be limited to a fixed license term (reported around three years) rather than indefinite use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Support options are more limited than on paid subscription tiers with dedicated success managers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Interface conventions can feel dated compared to newer, browser-based PDF tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$What is Nitro PDF Pro?$q$, $q$Nitro PDF Pro is a Windows desktop PDF editing application from Nitro Software that offers PDF creation, editing, conversion, OCR, and e-signature tools through a one-time purchase or multi-year license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$How much does Nitro PDF Pro cost?$q$, $q$Nitro PDF Pro has been offered around 250 dollars as a one-time license, distinct from Nitro's subscription plans which start around 15 dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Is Nitro PDF Pro available on Mac?$q$, $q$No, Nitro PDF Pro is Windows-only. Mac and iOS support is available through Nitro's subscription-based PDF Standard and Plus plans instead.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Who owns Nitro Software?$q$, $q$Nitro Software was founded in Melbourne, Australia in 2005 and, after being publicly listed on the Australian Securities Exchange, was taken private in March 2023 when Potentia Capital and HarbourVest Partners completed acquisition of the remaining public shares.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Does Nitro PDF Pro include OCR?$q$, $q$Yes, Nitro PDF Pro includes optical character recognition (OCR) for converting scanned documents into searchable, editable text.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$How does Nitro PDF Pro compare to Adobe Acrobat?$q$, $q$Nitro PDF Pro offers comparable core PDF editing, conversion, and e-signature functionality to Adobe Acrobat, typically at a lower price point, though Adobe maintains a broader ecosystem and more advanced enterprise features.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Does Nitro PDF Pro include electronic signatures?$q$, $q$Yes, Nitro PDF Pro includes built-in tools for filling and applying legally binding electronic signatures to PDF forms and documents.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Individual professional PDF editing$q$, $q$Professionals who occasionally need to edit, convert, or sign PDFs use Nitro PDF Pro's one-time purchase to avoid recurring subscription fees.$q$, $q$Individual professionals and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Small business document workflows$q$, $q$Small businesses use Nitro PDF Pro on Windows desktops to handle contracts, forms, and scanned paperwork without paying for a full enterprise subscription.$q$, $q$Small businesses and Windows-based offices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Digitizing scanned paperwork$q$, $q$Organizations with large volumes of scanned or paper documents use Nitro PDF Pro's OCR to convert them into searchable, editable digital files.$q$, $q$Administrative and back-office teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Nitro PDF Pro (one-time)$q$, $q$$250 one-time$q$, $q$one-time / multi-year license$q$, NULL, $q$["PDF creation and editing","OCR","Form filling and e-signature","Windows desktop application"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Nitro PDF Standard (subscription)$q$, $q$$15/month$q$, $q$monthly$q$, NULL, $q$["AI productivity features","Integrations","Nitro Admin Portal","24/7 support","Windows, Mac, and iOS support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$Nitro PDF Plus (subscription)$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Enterprise-grade security","Advanced analytics","Dedicated Customer Success Manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nitro PDF Pro is a Windows desktop PDF editing application built by Nitro Software, a company founded in Melbourne, Australia in 2005 specifically to offer a lower-cost alternative to Adobe Acrobat. The product covers the core tasks most PDF users need: creating, editing, converting, and combining PDF files, filling and signing forms, and running OCR on scanned documents.$q$, $q$Nitro PDF Pro is distinct from Nitro's newer cloud-based subscription products (Nitro PDF Standard and Plus). Where the subscription plans run across Windows, Mac, and iOS with AI features and team management built in, Nitro PDF Pro is a Windows-only desktop application, available as a one-time purchase or multi-year license rather than an ongoing subscription.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The application uses a Microsoft Office-style ribbon interface, making it familiar to users coming from Word or Excel. Core capabilities include full PDF editing (text, images, and pages), converting PDFs to and from formats like Word and Excel, combining multiple files into a single PDF, and filling and digitally signing forms.$q$, $q$Built-in OCR allows users to make scanned, image-based documents searchable and editable. As a perpetual-license product, Nitro PDF Pro does not include the AI productivity tools, advanced analytics, or dedicated customer success support reserved for Nitro's subscription tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nitro PDF Pro is available as a one-time purchase, reported at roughly 250 dollars per license, or as a multi-year license option, appealing to buyers who prefer to avoid ongoing subscription costs.$q$, $q$For comparison, Nitro's subscription lineup starts at around 15 dollars per month for the Nitro PDF Standard plan, which adds AI features and cross-platform support for Windows, Mac, and iOS, while the top-tier Plus plan is custom-quoted for larger organizations with enterprise security and support needs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Connects to existing SQL databases$q$, $q$Turns existing MySQL, Postgres, or SQL Server databases into a spreadsheet-style interface without requiring data migration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Multiple view types$q$, $q$Supports grid, gallery, kanban, calendar, form, and gantt-style views of the same underlying data for different workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Open-source and self-hostable$q$, $q$The Community edition is fair-code licensed and free to self-host with unlimited records, storage, and seats.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Automations and scripting$q$, $q$Lets teams build workflow automations and custom scripts to act on data changes without writing a full application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Role-based permissions$q$, $q$Controls access to bases and records by role, supporting private bases and granular team permissions on paid tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$API access$q$, $q$Exposes REST and other APIs for integrating NocoDB data with external applications and services.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Dashboards$q$, $q$Builds visual dashboards on top of underlying data for reporting and at-a-glance insights.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Row-level security and audit logs$q$, $q$Higher-tier plans add row-level security and audit logging for compliance-sensitive deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Free, self-hostable Community edition with unlimited records, storage, and seats$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Connects directly to existing production databases instead of requiring data migration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Strong open-source adoption with millions of downloads and tens of thousands of GitHub stars$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Backed by well-known angel investors from the open-source and tech community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Transparent, published pricing across both cloud and self-hosted tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Self-hosting requires technical setup and ongoing maintenance compared to a fully managed SaaS$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Smaller company and support team than Airtable, which may mean slower response times$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Some advanced features like SSO and row-level security are gated behind paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Cloud free tier's 1,000-record limit is restrictive for anything beyond small tests$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Interface and polish can lag behind more mature, heavily-funded no-code competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$What is NocoDB used for?$q$, $q$NocoDB is used to turn existing SQL databases or new data sets into a smart spreadsheet-style interface, letting teams build no-code apps, views, and workflows on top of their data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Is NocoDB really free?$q$, $q$Yes, NocoDB's Community edition is open source and fair-code licensed, allowing free self-hosting with unlimited records, storage, and seats. Paid cloud and self-hosted plans add features like SSO, audit logs, and higher usage limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$How is NocoDB different from Airtable?$q$, $q$NocoDB is open source and can connect directly to existing production SQL databases, while Airtable is a closed, proprietary platform that requires data to live within its own system.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Who founded NocoDB?$q$, $q$NocoDB was founded by UK-based founder and CEO Naveen Rudrappa, with the open-source project first released around 2019.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Can NocoDB be self-hosted?$q$, $q$Yes, NocoDB can be self-hosted for free using its open-source Community edition, or organizations can use NocoDB's managed cloud offering instead.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$How much does NocoDB's cloud plan cost?$q$, $q$NocoDB's cloud pricing starts with a free tier, then Plus at 12 dollars per user per month, Business at 24 dollars per user per month, and Scale at 45 dollars per user per month, all billed annually.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Has NocoDB raised funding?$q$, $q$Yes, NocoDB has raised approximately 10.5 million dollars in seed funding from investors including Decibel, OSS Capital, Uncorrelated Ventures, and Together Fund, along with several notable angel investors.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Building internal tools on production data$q$, $q$Engineering and operations teams use NocoDB to build spreadsheet-style internal tools directly on top of existing production databases without duplicating data.$q$, $q$Engineering and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Self-hosted data control for privacy-sensitive teams$q$, $q$Organizations with strict data residency or privacy requirements self-host NocoDB's open-source Community edition to keep full control of their infrastructure.$q$, $q$Privacy-conscious organizations and regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$No-code app building for small teams$q$, $q$Small teams and startups use NocoDB's views, automations, and dashboards to build lightweight apps and workflows without hiring developers.$q$, $q$Startups and small business teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Community (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited records, storage, and seats","All 5 roles included","6 view types","Conditional webhooks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Cloud Free$q$, $q$$0/user/month$q$, $q$monthly$q$, NULL, $q$["1,000 records","1 GB storage","100 automation runs/month","1,000 API calls/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Cloud Plus$q$, $q$$12/user/month$q$, $q$annual$q$, NULL, $q$["50,000 records","20 GB storage","10,000 automation runs/month","Unlimited extensions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Cloud Business$q$, $q$$24/user/month$q$, $q$annual$q$, NULL, $q$["300,000 records","100 GB storage","Private bases","SAML SSO"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Cloud Scale$q$, $q$$45/user/month$q$, $q$annual$q$, NULL, $q$["1,000,000 records","150 GB storage","Row-level security","Audit logs"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["SCIM","Air-gapped installation","Dedicated CSM","Whitelabeling"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NocoDB is an open-source, self-hostable no-code database platform often described as a free alternative to Airtable. Founded by UK-based CEO Naveen Rudrappa with the open-source project emerging around 2019, NocoDB's core differentiator is that it can connect directly to existing SQL databases -- including production databases like MySQL and Postgres -- and turn them into a smart, spreadsheet-style interface, rather than requiring data to be migrated into a proprietary format.$q$, $q$This approach was highlighted in TechCrunch's October 2022 coverage of the company, which framed NocoDB as taking on Airtable by working with production data directly. The project has become one of the more widely adopted open-source no-code tools, with millions of Docker downloads and tens of thousands of GitHub stars.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$NocoDB offers multiple ways to view the same underlying data, including grid, gallery, kanban, calendar, and form views, so different team members can interact with data in the format that suits their workflow. Automations, scripting, and dashboards let teams build lightweight internal tools and workflows without a dedicated engineering project.$q$, $q$Because it is fair-code licensed and open source, the Community edition can be self-hosted for free with unlimited records, storage, and seats, appealing strongly to developers and organizations that want full control over their data and infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NocoDB's self-hosted Community edition is free forever with unlimited records, storage, and seats. Paid cloud plans start with a free tier (1,000 records, 1 GB storage) and step up to Plus at 12 dollars per user per month, Business at 24 dollars per user per month, and Scale at 45 dollars per user per month, all billed annually.$q$, $q$Self-hosted Business and Scale tiers offer similar feature sets to their cloud counterparts, priced per editor rather than per total seat, with a custom-quoted Enterprise tier available for organizations needing SCIM, air-gapped deployment, and dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e0b83b6-71ce-4357-81d5-6f9274821112', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
